import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"无限爆炸物系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/爆炸物/系列武器/无限爆炸物系列.md","filePath":"4.资源分区/7.物品与装备/2.武器/爆炸物/系列武器/无限爆炸物系列.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/爆炸物/系列武器/无限爆炸物系列.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"无限爆炸物系列",tabindex:"-1"},[p("无限爆炸物系列 "),r("a",{class:"header-anchor",href:"#无限爆炸物系列","aria-label":'Permalink to "无限爆炸物系列"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),n('<h1 id="无限爆炸物系列-1" tabindex="-1">无限爆炸物系列 <a class="header-anchor" href="#无限爆炸物系列-1" aria-label="Permalink to &quot;无限爆炸物系列&quot;">​</a></h1><p>无限爆炸物系列<br> 描述：出自《夜之猎魔少女》的系列爆炸物，经过主神改良这些爆炸物皆可以无限的取出并进行使用。值得注意的是，该系列的物品与基础爆炸物中的同名物品并不是一回事。<br> 若购买该系列爆炸物，将会赠送必须的发射器和储物口袋，通常每种爆炸物只能同时存在一个，需要在使用后正常重新取出（受取出武器的专长效果影响）。</p><p>该系列爆炸物在无特殊说明的情况下，总是不会造成友军伤害，效果自然也不会波及友方，包括使用者在内。</p><p>布置类爆炸物同时存在多个，允许随时引爆，因此可以在场景开始前布置额外不限制数量的爆炸物。（显然的，多个爆炸物叠加并不会使范围内的单位受到多次伤害，但可能因为范围交互而带来爆炸范围的扩展。）</p><p>投掷类爆炸物需要通过力量进行投掷，专业为力量+投掷，取得一个成功数就可以正常投掷出，射程为力量*10米，投掷类爆炸物将会在掷出到指定位置后立刻爆炸。若无特殊说明，则需要使用反射豁免爆炸物造成的固定伤害，非固定伤害正常计算。</p><p>发射类爆炸物必须使用移动动作进行填装，即使你的弹药实际上是无限量的，使用的检定为射击类检定，专业：炮，但只需要取得1个成功数即正常使对方进行对于固定伤害的反射豁免。</p><p>无论的是投掷类还是发射类爆炸物都需要进行一个前置动作，如拉开拉环，调试发射器等等，这会消耗掉你的一个迅捷动作。但使用预设进行攻击的发射类爆炸物无需消耗迅捷动作。</p><p>【毁灭】使用前进行一次D10的自然骰，若结果为8，9，10，则使本次爆炸物的固定伤害提升1/3，连续3次不触发毁灭时，则下一次攻击必然触发毁灭。<br> 【湮灭】使用前进行一次D10的自然骰，若结果为8，9，10，则使本次爆炸物的固定伤害提升一倍，连续3次不触发湮灭时，则下一次攻击必然触发湮灭。</p><p>破片手榴弹/燃烧手榴弹/液氮瓶<br> 价格：D+500<br> 固定伤害：10L<br> 特性：无<br> 爆炸范围：15米<br> 描述：分类三种类型的特制爆炸物，可以分别造成物理穿刺伤害，火焰伤害，以及寒冷伤害。<br> 额外效果：你需要在购买时进行选择，从这三种投掷类爆炸物中选择一种获得，破片手榴弹会在处理目标反射检定时，使对方检定结果减少你的传奇敏捷*1点。<br> 燃烧手榴弹会附带1点不可豁免，可叠加的燃烧不良点数，同时使伤害类型转变为火焰伤害。<br> 液氮瓶会附带1点不可豁免，可叠加的冻结不良点数，同时使伤害类型转变为寒冷伤害。</p><p>烟幕爆破弹/闪光爆破弹/冷凝弹<br> 价格：D+500<br> 固定伤害：10L<br> 特性：无<br> 爆炸范围：15米<br> 描述：特制的烟雾弹与闪光弹，可以在投掷造成爆破杀伤的同时产生强烈的烟雾或是闪光。<br> 效果：烟幕爆破弹在爆炸范围内造成浓烈的烟幕，不过这种烟幕只会对范围内的友方单位（包括自身）提供3点掩蔽防御与3点潜藏行为相关检定的加值。<br> ——<br> 闪光爆破弹不会造成伤害，但目标需要使用强韧豁免进行一次检定，以固定伤害为DC进行对抗，失败则陷入C级创伤来源的【目盲】状态，这种【目盲】效果会持续一轮。<br> ——<br> 冷凝弹会使受到伤害的目标使用反射豁免再进行一次检定，固定伤害为DC进行对抗，失败则陷入C级环境来源的【潮湿】状态，这种【潮湿】效果会持续一场景。</p><p>C4炸药<br> 价格：C+1500<br> 固定伤害：15L<br> 特性：【毁灭】【破甲5】<br> 爆炸范围：15+布置者传奇智力*5米<br> 描述：C4炸药是一种布置类爆炸物，事实上这玩意的爆炸威力强的惊人，说不定连战车都能炸翻……至少原作版本是这样。<br> 额外效果：<br> *该爆炸物是布置类爆炸物，因此遵循爆炸物规则中的计算需求，布置DC7。<br> *该爆炸物正常应用布置爆炸物、仓促布置/高难应用等规则。通常情况下，你在布置时可以每轮重复检定，多次积累成功数到达DC即可正常引爆，附带无限量可以使用的定时引信与远程引爆装置。<br> *在爆炸范围内的所有单位需要使用反射检定豁免伤害，显而易见的可能发生杀伤半径比投掷半径更大的问题，不过你大可以随时远程引爆。</p><p>40mm榴弹<br> 价格：C+2000<br> 描述：采用复古的单发装填，很有纪念意义设计的下挂式榴弹发射器，你可以随便把它挂在枪械或者非枪械武器上使用。<br> 效果：<br> 购买时会赠送一把专门用来挂发射器的模型枪。<br> 很显然，这是一把独特的发射类爆炸物，它采用的是预设攻击，内置攻击预设为42DP+4附加，弹容量1，具有【破甲10】，射程为100米，伤害类型为物理-穿刺。</p><p>RPG-7反战车榴弹<br> 价格：C+1000<br> 固定伤害：15L<br> 特性：【毁灭】<br> 弹容量：1<br> 射程：100米<br> 伤害类型：物理-穿刺<br> 描述：被称之为传奇武器RPG-7反战车榴弹，设计上采用了便携肩抗式榴弹发射器，简单，高效，以及最关键的：威力巨大。不过主神版本的发射器有效射程只有原版的一半左右。<br> 额外效果：该发射类爆炸物只能造成单体伤害，而不是范围伤害，但目标依旧需要使用反射豁免。</p><p>火箭弹组合<br> 前置：RPG-7反战车榴弹<br> 价格：B+2000（逐级）<br> 固定伤害：20L<br> 特性：【湮灭】<br> 射程：100米<br> 描述：被称之为“死神”的火箭弹组合套装，不单单只是对于榴弹本身进行了改良，也对发射器进行了进一步的升级，内部填装了化学武器，因此还会造成多方面的效果。<br> 效果：<br> 使用该发射类武器进行攻击是一个不能附带任何招式与其他效果的标准动作攻击，该武器的固定伤害将提升持有者智力*1点，可以对于前方扇形范围内的所有敌人造成伤害，附带等同于伤害的反胃不良点数，正常豁免。</p><p>致命·标枪导弹<br> 前置：火箭弹组合<br> 价格：A+4000（逐级）<br> 固定伤害：30L<br> 特性：【湮灭】<br> 射程：100米<br> 描述：好危险！系列产品，不过因为版权问题名称变成了致命·标枪导弹。虽然看起来只是标枪导弹的规格，但内部蕴含的力量全然不亚于主神牌微型核弹级别的威力。<br> 效果：<br> 在【火箭弹组合】效果的基础上，该武器的【湮灭】改为6、7、8、9、10都可以触发，同时射程还会提升使用者传奇智力*50米，且最终结算时射程翻倍，这同样意味着好危险！武器造成的伤害是不分敌我的，会因为【火箭弹】组合的效果导致对于前方扇形范围内的所有目标进行范围伤害。<br> ——<br> 过于强大的杀伤会导致环境的剧烈变化，该武器作用的范围内会在该场景内变为【失重】环境，同时具有强烈的辐射，位于其中的单位每分钟都需要进行一个DC为19的强韧豁免检定，若失败则受到1点耐力属性伤害。每在此环境滞留一个小时，强韧豁免的DC就提升1点，这些效果是A级的环境来源影响。<br> 辐射只会持续一场景是因为主神加工对于该武器进行了部分无害化，使其辐射持续能力降低，成为了轻污染的清洁武器，三防也会相应免疫该效果带来的辐射，但无法免疫失重影响。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const D=e(s,[["render",o]]);export{C as __pageData,D as default};
